  1	import * as React from 'react';
  2	import { LSO_OPERATOR } from '@odf/core/constants';
  3	import { expandStorageUXBackendEndpoint } from '@odf/core/constants/attach-storage';
  4	import { useNodesData, useSafeK8sGet } from '@odf/core/hooks';
  5	import { useODFSystemFlagsSelector } from '@odf/core/redux';
  6	import { pvResource } from '@odf/core/resources';
  7	import { NodeData } from '@odf/core/types';
  8	import {
  9	  checkArbiterCluster,
 10	  checkFlexibleScaling,
 11	  getDeviceSetCount,
 12	  getSCAvailablePVs,
 13	} from '@odf/core/utils';
 14	import { getCephNodes } from '@odf/ocs/utils';
 15	import {
 16	  PageHeading,
 17	  StatusBox,
 18	  StorageClusterKind,
 19	  StorageClusterModel,
 20	  useFetchCsv,
 21	} from '@odf/shared';
 22	import { isCSVSucceeded, referenceForModel } from '@odf/shared/utils';
 23	import {
 24	  consoleFetch,
 25	  K8sResourceCommon,
 26	  useK8sWatchResource,
 27	} from '@openshift-console/dynamic-plugin-sdk';
 28	import { useTranslation } from 'react-i18next';
 29	import {
 30	  useLocation,
 31	  useNavigate,
 32	  useParams,
 33	} from 'react-router-dom-v5-compat';
 34	import { Text, TextContent, TextVariants } from '@patternfly/react-core';
 35	import { createWizardNodeState, getDeviceSetReplica } from '../utils';
 36	import { AttachStorageFormFooter } from './attach-storage-footer';
 37	import './attach-storage.scss';
 38	import DeviceClassForm from './device-class-form';
 39	import { LSOStorageClassDropdown } from './lso-storageclass-dropdown';
 40	import {
 41	  AttachStorageActionType,
 42	  AttachStoragePayload,
 43	  attachStorageReducer,
 44	  createPayload,
 45	  initialAttachStorageState,
 46	} from './state';
 47	import StoragePoolForm from './storage-pool-form';
 48	import StorageClassForm from './storageclass-form';
 49	
 50	const sendPostRequest = async (payload: AttachStoragePayload) => {
 51	  const response = await consoleFetch(expandStorageUXBackendEndpoint, {
 52	    method: 'POST',
 53	    body: JSON.stringify(payload),
 54	    headers: {
 55	      'Content-Type': 'application/json',
 56	    },
 57	  });
 58	
 59	  if (!response.ok) {
 60	    const errorMessage = `HTTP error! Status: ${response.status}`;
 61	    throw new Error(errorMessage);
 62	  }
 63	};
 64	
 65	const AttachStorage = () => {
 66	  const { t } = useTranslation();
 67	  const { resourceName, namespace } = useParams();
 68	  const location = useLocation();
 69	  const [state, dispatch] = React.useReducer(
 70	    attachStorageReducer,
 71	    initialAttachStorageState
 72	  );
 73	  const navigate = useNavigate();
 74	  const [csv, csvLoaded, csvLoadError] = useFetchCsv({
 75	    specName: LSO_OPERATOR,
 76	  });
 77	
 78	  const isLSOInstalled = csvLoaded && !csvLoadError && isCSVSucceeded(csv);
 79	  const [pvData, pvLoaded, pvLoadError] =
 80	    useK8sWatchResource<K8sResourceCommon[]>(pvResource);
 81	
 82	  React.useEffect(() => {
 83	    if (csvLoaded && !isLSOInstalled) {
 84	      navigate(
 85	        `/odf/system/ns/${namespace}/${referenceForModel(
 86	          StorageClusterModel
 87	        )}/${resourceName}`
 88	      );
 89	    }
 90	  }, [csvLoaded, isLSOInstalled, navigate, namespace, resourceName]);
 91	
 92	  const { systemFlags, areFlagsLoaded, flagsLoadError } =
 93	    useODFSystemFlagsSelector();
 94	  const clusterName = systemFlags[namespace]?.ocsClusterName;
 95	
 96	  const [storageCluster, storageClusterLoaded, storageClusterLoadError] =
 97	    useSafeK8sGet<StorageClusterKind>(
 98	      StorageClusterModel,
 99	      clusterName,
100	      namespace
101	    );
102	
103	  const [nodesData, nodesLoaded, nodesLoadError] = useNodesData();
104	
105	  const breadcrumbs = [
106	    {
107	      name: resourceName,
108	      path: `${location.pathname.split(`/~attachstorage`)[0]}`,
109	    },
110	    {
111	      name: t('Attach Storage'),
112	      path: '',
113	    },
114	  ];
115	
116	  const onClose = React.useCallback(() => {
117	    navigate(-1);
118	  }, [navigate]);
119	
120	  const onConfirm = React.useCallback(async () => {
121	    if (
122	      !storageClusterLoaded ||
123	      storageClusterLoadError ||
124	      !nodesLoaded ||
125	      nodesLoadError ||
126	      !pvLoaded ||
127	      pvLoadError
128	    ) {
129	      dispatch({
130	        type: AttachStorageActionType.SET_ERROR_MESSAGE,
131	        payload: t('Required data is not available. Please try again later.'),
132	      });
133	      return;
134	    }
135	
136	    if (!pvData.length) {
137	      dispatch({
138	        type: AttachStorageActionType.SET_ERROR_MESSAGE,
139	        payload: t('No Persistent Volumes are available.'),
140	      });
141	      return;
142	    }
143	
144	    if (!nodesData.length) {
145	      dispatch({
146	        type: AttachStorageActionType.SET_ERROR_MESSAGE,
147	        payload: t('No nodes data is available.'),
148	      });
149	      return;
150	    }
151	
152	    try {
153	      dispatch({ type: AttachStorageActionType.SET_INPROGRESS, payload: true });
154	      const hasFlexibleScaling = checkFlexibleScaling(storageCluster);
155	      const isArbiterEnabled: boolean = checkArbiterCluster(storageCluster);
156	
157	      const replica = getDeviceSetReplica(
158	        isArbiterEnabled,
159	        hasFlexibleScaling,
160	        createWizardNodeState(getCephNodes(nodesData, namespace) as NodeData[])
161	      );
162	
163	      const pvs: K8sResourceCommon[] = getSCAvailablePVs(
164	        pvData,
165	        state.lsoStorageClassName
166	      );
167	      const availablePvsCount = pvs.length || 0;
168	      const failureDomain = storageCluster?.status?.failureDomain;
169	      const deviceSetCount = getDeviceSetCount(availablePvsCount, replica);
170	      const filesystemName = `${clusterName}-cephfilesystem`;
171	      const payload = createPayload(
172	        state,
173	        clusterName,
174	        failureDomain,
175	        replica,
176	        filesystemName,
177	        deviceSetCount
178	      );
179	      await sendPostRequest(payload);
180	      onClose();
181	    } catch (error) {
182	      dispatch({
183	        type: AttachStorageActionType.SET_ERROR_MESSAGE,
184	        payload: error.message || t('An unexpected error has occured.'),
185	      });
186	    } finally {
187	      dispatch({
188	        type: AttachStorageActionType.SET_INPROGRESS,
189	        payload: false,
190	      });
191	    }
192	  }, [
193	    t,
194	    storageCluster,
195	    storageClusterLoaded,
196	    storageClusterLoadError,
197	    nodesData,
198	    nodesLoaded,
199	    nodesLoadError,
200	    pvData,
201	    pvLoaded,
202	    pvLoadError,
203	    state,
204	    namespace,
205	    dispatch,
206	    clusterName,
207	    onClose,
208	  ]);
209	
210	  const isLoaded =
211	    csvLoaded &&
212	    nodesLoaded &&
213	    areFlagsLoaded &&
214	    pvLoaded &&
215	    storageClusterLoaded;
216	  const isLoadError =
217	    flagsLoadError ||
218	    csvLoadError ||
219	    nodesLoadError ||
220	    storageClusterLoadError ||
221	    pvLoadError;
222	
223	  const deviceSets = React.useMemo(
224	    () => storageCluster?.spec?.storageDeviceSets || [],
225	    [storageCluster?.spec?.storageDeviceSets]
226	  );
227	
228	  const selectedStorageClassCount =
229	    deviceSets?.filter(
230	      (ds) =>
231	        ds.dataPVCTemplate?.spec?.storageClassName === state.lsoStorageClassName
232	    )?.length || 0;
233	
234	  const defaultDeviceClassName =
235	    selectedStorageClassCount === 0
236	      ? state.lsoStorageClassName
237	      : `${state.lsoStorageClassName}-${selectedStorageClassCount}`;
238	
239	  React.useEffect(() => {
240	    if (!state.lsoStorageClassName) return;
241	
242	    dispatch({
243	      type: AttachStorageActionType.SET_DEVICE_CLASS,
244	      payload: defaultDeviceClassName,
245	    });
246	  }, [state.lsoStorageClassName, defaultDeviceClassName, dispatch]);
247	
248	  return (
249	    <>
250	      <PageHeading title={t('Attach Storage')} breadcrumbs={breadcrumbs}>
251	        <TextContent className="attachstorage__description">
252	          <Text component={TextVariants.small}>
253	            {t('Attach a new storage device class set to {{ resourceName }}', {
254	              resourceName,
255	            })}
256	          </Text>
257	        </TextContent>
258	      </PageHeading>
259	      {!isLoaded || isLoadError ? (
260	        <div className="pf-v6-u-pb-xl">
261	          <StatusBox
262	            loaded={isLoaded}
263	            loadError={isLoadError}
264	            label={t('Attach Storage form')}
265	          />
266	        </div>
267	      ) : (
268	        <div className="attachstorage-form">
269	          <LSOStorageClassDropdown
270	            dispatch={dispatch}
271	            storageCluster={storageCluster}
272	            namespace={namespace}
273	            state={state}
274	          />
275	          {selectedStorageClassCount > 0 && (
276	            <DeviceClassForm
277	              state={state}
278	              dispatch={dispatch}
279	              deviceSets={deviceSets}
280	              defaultDeviceClass={defaultDeviceClassName}
281	            />
282	          )}
283	          <div className="storagepool-form">
284	            <StoragePoolForm
285	              state={state}
286	              dispatch={dispatch}
287	              clusterName={clusterName}
288	            />
289	          </div>
290	          <StorageClassForm state={state} dispatch={dispatch} />
291	          <AttachStorageFormFooter
292	            state={state}
293	            cancel={onClose}
294	            onConfirm={onConfirm}
295	          />
296	        </div>
297	      )}
298	    </>
299	  );
300	};
301	export default AttachStorage;

